import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { api } from '../services/api';
import './ProblemsPage.css';

function ProblemsPage() {
  const navigate = useNavigate();
  const [problems, setProblems] = useState([]);
  const [filter, setFilter] = useState('');
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [problemsData, userData] = await Promise.all([
        api.getProblems(),
        api.getCurrentUser()
      ]);
      setProblems(problemsData);
      setUser(userData);
    } catch (error) {
      console.error('Failed to load data:', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredProblems = filter
    ? problems.filter(p => p.difficulty === filter)
    : problems;

  const handleLogout = () => {
    localStorage.removeItem('token');
    window.location.href = '/login';
  };

  if (loading) {
    return <div className="loading">Loading...</div>;
  }

  return (
    <div className="problems-page">
      <nav className="navbar">
        <div className="nav-brand">
          <span className="brand-icon">🚀</span>
          <span className="brand-text">Abzorithm</span>
        </div>
        <div className="nav-menu">
          <button className="nav-link active">
            <span className="nav-icon">📝</span>
            <span>Problems</span>
          </button>
          <button className="nav-link" onClick={() => navigate('/leaderboard')}>
            <span className="nav-icon">🏆</span>
            <span>Leaderboard</span>
          </button>
        </div>
        <div className="nav-user">
          <div className="user-score">
            <span className="score-icon">⭐</span>
            <span className="score-value">{user?.score || 0}</span>
          </div>
          <div className="user-avatar">{user?.username?.charAt(0).toUpperCase()}</div>
          <button onClick={handleLogout} className="btn-logout">
            <span>🚪</span>
            <span>Logout</span>
          </button>
        </div>
      </nav>

      <div className="content">
        <div className="page-header">
          <div>
            <h1>Problems</h1>
            <p>Practice and improve your coding skills</p>
          </div>
          <select value={filter} onChange={(e) => setFilter(e.target.value)} className="filter">
            <option value="">All Difficulties</option>
            <option value="Easy">Easy</option>
            <option value="Medium">Medium</option>
            <option value="Hard">Hard</option>
          </select>
        </div>

        <div className="problems-table">
          <div className="table-header">
            <div>Status</div>
            <div>Title</div>
            <div>Difficulty</div>
          </div>
          {filteredProblems.map(problem => (
            <div 
              key={problem.id} 
              className="problem-row"
              onClick={() => navigate(`/problem/${problem.id}`)}
            >
              <div>○</div>
              <div>
                <div className="problem-title">{problem.title}</div>
                {problem.tags && (
                  <div className="tags">
                    {problem.tags.split(',').slice(0, 3).map((tag, i) => (
                      <span key={i} className="tag">{tag.trim()}</span>
                    ))}
                  </div>
                )}
              </div>
              <div>
                <span className={`badge ${problem.difficulty}`}>
                  {problem.difficulty}
                </span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default ProblemsPage;
